import java.util.*;
import java.util.stream.*;

public class Main {
    public static void main(String[] args) {
        List<Integer> numbers = List.of(1, 2, 3, 4, 5, 6);

        // BEFORE: the old loop way
        System.out.println("Loop way:");
        for (int n : numbers) {
            if (n % 2 == 0) {
                System.out.println(n);
            }
        }

        // AFTER: the stream way (same result)
        System.out.println("Stream way:");
        numbers.stream()
               .filter(n -> n % 2 == 0)
               .forEach(n -> System.out.println(n));
    }
}

import java.util.*;
import java.util.stream.*;

public class Main {
    public static void main(String[] args) {
        List<String> names = List.of("ada", "alan", "grace");

        // map with a method reference, then collect into a new list
        List<String> shouting = names.stream()
                                     .map(String::toUpperCase)
                                     .collect(Collectors.toList());
        System.out.println(shouting);

        List<Integer> prices = List.of(10, 25, 5, 60);
        int total = prices.stream()
                          .mapToInt(p -> p)
                          .sum();
        System.out.println("Total price: " + total);

        long howMany = prices.stream()
                            .filter(p -> p > 10)
                            .count();
        System.out.println("Items over 10: " + howMany);
    }
}

