import java.util.*;
import java.util.stream.*;

public class Main {
    public static void main(String[] args) {
        List<Integer> cart = List.of(15, 8, 40, 3, 22);

        int total = cart.stream()
                       .filter(price -> price > 10)
                       .mapToInt(price -> price)
                       .sum();

        long count = cart.stream()
                        .filter(price -> price > 10)
                        .count();

        System.out.println("Expensive items: " + count);
        System.out.println("Total of expensive items: " + total);
    }
}
